def find_active_regions(    wavelength,    opacity,    threshold=0.15,):    """    Return wavelength intervals where the opacity    exceeds a given threshold.    Returns    -------    list[tuple]        [(start, end), ...]    """    mask = opacity >= threshold    regions = []    inside = False    for wl, active in zip(wavelength, mask):        if active and not inside:            start = wl            inside = True        elif not active and inside:            end = wl            regions.append((start, end))            inside = False    if inside:        regions.append((start, wavelength.iloc[-1]))    return regions